# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import NoBrokersAvailable

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config_settings):
    topic_config = {k: v for k, v in config_settings} if config_settings else {}
    new_topic = NewTopic(
        name=topic_name,
        num_partitions=num_partitions,
        replication_factor=replication_factor,
        topic_configs=topic_config
    )
    try:
        admin_client.create_topics(new_topics=[new_topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully with {num_partitions} partitions and replication factor {replication_factor}.")
        if topic_config:
            print(f"  Configuration settings: {topic_config}")
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_metadata = admin_client.describe_topics([topic_name])
        if not topic_metadata:
            print(f"Topic '{topic_name}' not found.")
            return

        print(f"--- Describing Topic: {topic_name} ---")
        for metadata in topic_metadata:
            print(f"  Name: {metadata.name}")
            print(f"  ID: {metadata.topic_id}")
            print(f"  Partitions: {len(metadata.partitions)}")
            for partition in metadata.partitions:
                print(f"    Partition {partition.id}: Leader {partition.leader.nodeId}, Replicas {[r.nodeId for r in partition.replicas]}, ISR {[isr.nodeId for isr in partition.isr]}")
            print(f"  Is Internal: {metadata.is_internal}")

        # Fetch config for the topic
        config_resources = [ConfigResource(ConfigResourceType.TOPIC, topic_name)]
        topic_configs = admin_client.describe_configs(config_resources)
        print("  Configurations:")
        for res in topic_configs:
            for entry in res.entries:
                if not entry.is_default or not entry.is_read_only: # Only show non-default or non-read-only configs
                    print(f"    {entry.name}: {entry.value} (Default: {entry.is_default}, ReadOnly: {entry.is_read_only}, Sensitive: {entry.is_sensitive}, Source: {entry.source.name})")

    except Exception as e:
        print(f"Error describing topic '{topic_name}': {e}")

def alter_topic_configs(admin_client, topic_name, config_settings):
    if not config_settings:
        print("No configuration settings provided for alteration.")
        return

    config_entries = {k: v for k, v in config_settings}
    resource = ConfigResource(ConfigResourceType.TOPIC, topic_name, config_entries)
    try:
        admin_client.alter_configs([resource])
        print(f"Topic '{topic_name}' configurations altered successfully.")
        print(f"  New configuration settings: {config_entries}")
    except Exception as e:
        print(f"Error altering topic '{topic_name}' configurations: {e}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics([topic_name])
        print(f"Topic '{topic_name}' deleted successfully.")
    except Exception as e:
        print(f"Error deleting topic '{topic_name}': {e}")

def list_topics(admin_client):
    try:
        topic_names = admin_client.list_topics()
        print("--- Existing Topics ---")
        if topic_names:
            for topic in sorted(topic_names):
                print(f"- {topic}")
        else:
            print("No topics found.")
    except Exception as e:
        print(f"Error listing topics: {e}")

def main():
    parser = argparse.ArgumentParser(description="Kafka Topic Administration Script")
    parser.add_argument("--bootstrap-servers", default="localhost:9092", help="Comma-separated list of Kafka bootstrap servers")
    parser.add_argument("action", choices=["create", "describe", "alter-config", "delete", "list"], help="Action to perform (create, describe, alter-config, delete, list)")
    parser.add_argument("--topic", help="Name of the topic")
    parser.add_argument("--partitions", type=int, help="Number of partitions for the topic (required for create)")
    parser.add_argument("--replication-factor", type=int, help="Replication factor for the topic (required for create)")
    parser.add_argument("--config", nargs='*', metavar="KEY=VALUE", help="Topic configuration settings (e.g., retention.ms=604800000 clean.up.policy=compact)")

    args = parser.parse_args()

    if args.action in ["create", "describe", "alter-config", "delete"] and not args.topic:
        parser.error(f"The --topic argument is required for action '{args.action}'.")

    if args.action == "create":
        if not args.partitions or not args.replication_factor:
            parser.error("The --partitions and --replication-factor arguments are required for 'create' action.")

    config_settings = []
    if args.config:
        for item in args.config:
            if '=' not in item:
                parser.error(f"Invalid config format: '{item}'. Expected KEY=VALUE.")
            config_settings.append(item.split('=', 1))

    try:
        admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_servers, client_id='kafka_admin_script')
        print(f"Connected to Kafka bootstrap servers: {args.bootstrap_servers}")
    except NoBrokersAvailable:
        print(f"Error: No Kafka brokers available at {args.bootstrap_servers}. Please check your connection and broker status.")
        return
    except Exception as e:
        print(f"Error connecting to Kafka: {e}")
        return

    try:
        if args.action == "create":
            create_topic(admin_client, args.topic, args.partitions, args.replication_factor, config_settings)
        elif args.action == "describe":
            describe_topic(admin_client, args.topic)
        elif args.action == "alter-config":
            alter_topic_configs(admin_client, args.topic, config_settings)
        elif args.action == "delete":
            delete_topic(admin_client, args.topic)
        elif args.action == "list":
            list_topics(admin_client)
    finally:
        try:
            admin_client.close()
            print("KafkaAdminClient closed.")
        except Exception as e:
            print(f"Error closing KafkaAdminClient: {e}")

if __name__ == "__main__":
    main()